                <!-- <v-col><v-btn depressed outlined @click="codingshow = false; mathshow = false; mathshow1 = false" class="FirstBtn" color="primary"><firstbtn>科学</firstbtn></v-btn></v-col> -->
                <!-- <v-col><v-btn depressed outlined @click="mathshow = false; mathshow1 = false; codingshow = !codingshow" class="FirstBtn" color="primary"><firstbtn>编程</firstbtn></v-btn></v-col> -->
                <v-col></v-col>
                <v-col></v-col>
