                        <v-card-actions>
                          <router-link to="../downloads"><v-btn text @click="mathshow1 = showHD; showHD = !showHD; showKS = false;" class="SecondBtn">前往</v-btn></router-link>
                        </v-card-actions>
                      </v-card>
                    </div>
                  </v-col>
                </v-row>
              </transition>
            </v-main>
          </v-container>
        </v-container>
      </transition>

    </v-app>

  </div>
</template>

<script>
import firstbtn from '../components/firstbtn'
import secondbtn from '../components/secondbtn'
export default {
  name: 'questionbank',
  components: {
    firstbtn,
    secondbtn
  },
  data: () => {
    return {
      mathshow: false,
      showKS: false,
      showHD: false,
