      years: [/*'一年级', '二年级', */'三年级', '四年级', '五年级', '六年级'],
      updown: ['上学期', '下学期'],
      upd: '',
      year223:'',
      year223s: ['一年级', '二年级', '三年级', '四年级', '五年级', '六年级', '初一', '初二', '初三'],
      codingshow: false,
