      all: '',
      playing: false,
      little: 0,
      isSuccess: false,
      showOption: true
    }
  },
  methods: {
    submitButtonCount() {
      let gra = this.year
      let grade = 0
      /*if(gra === '一年级') {
        grade = 1
      }
      else if(gra === '二年级') {
        grade = 2
      }
      else */if(gra === '三年级') {
        grade = 3
      }
      else if(gra === '四年级') {
        grade = 4
      }
      else if(gra === '五年级') {
        grade = 5
      }
      else if(gra === '六年级') {
        grade = 6
      }
      let semester = (this.upd === '上学期')? true : false
      /*if(grade == 1) {
        if(semester) {
          this.practice = ['1~5的认识和加减法', '6~10的认识和加减法', '20以内的加法', '20以内的连加']
        }
        else {
          this.practice = ['20以内的减法', '20以内的连减', '20以内的加减混合']
        }
      }
      else if(grade == 2) {
        if(semester) {
          this.practice = ['两位数加两位数', '两位数减两位数', '两位数连加', '两位数连减', '两位数的加减混合', '表内乘法']
        }
        else {
          this.practice = ['表内除法', '混合运算', '有余数的除法']
        }
      }
      else */if(grade == 3) {
        if(semester) {
          this.practice = ['多位数乘一位数']
        }
        else {
          this.practice = ['除数是一位数的除法', '两位数乘两位数']
        }
      }
      else if(grade == 4) {
        if(semester) {
          this.practice = ['三位数乘两位数', '除数是两位数的除法']
        }
        else {
          this.practice = ['小数的加法和减法']
        }
      }
      else if(grade == 5) {
        if(semester) {
          this.practice = ['小数乘法', '小数除法']
        }
        else {
          this.practice = ['分数的加减法']
        }
      }
      else if(grade == 6) {
        if(semester) {
          this.practice = ['分数乘法', '分数除法']
        }
        else {
          this.practice = ['带有百分数的计算']
        }
      }
      this.showKS2 = true
    },
    submitButtonThinking() {
      let gra = this.year233
      let grade = 0
      if(gra === '一年级') {
        grade = 1
      }
      else if(gra === '二年级') {
        grade = 2
      }
      else if(gra === '三年级') {
        grade = 3
      }
      else if(gra === '四年级') {
        grade = 4
      }
      else if(gra === '五年级') {
        grade = 5
      }
      else if(gra === '六年级') {
        grade = 6
      }
      else if(gra === '初一') {
        grade = 7
      }
      else if(gra === '初二') {
        grade = 8
      }
      else if(gra === '初三') {
        grade = 9
      }
    },
    submitButtonCountStart() {
      if(this.counts >= 0) {
        this.playing = true
      }
      
      let ctnt
      if(this.content == '多位数乘一位数') {
        ctnt = 0
      }
      else if(this.content == '除数是一位数的除法') {
        ctnt = 1
      }
      else if(this.content == '两位数乘两位数') {
        ctnt = 2
      }
      else if(this.content == '三位数乘两位数') {
        ctnt = 3
      }
      else if(this.content == '除数是两位数的除法') {
        ctnt = 4
      }
      else if(this.content == '四则运算') {
        ctnt = 5
      }
      else if(this.content == '运算定律') {
        ctnt = 6
      }
      else if(this.content == '小数的加法和减法') {
        ctnt = 7
      }
      else if(this.content == '小数乘法') {
        ctnt = 8
      }
      else if(this.content == '小数除法') {
        ctnt = 9
      }
      else if(this.content == '分数的加减法') {
        ctnt = 10
      }
      else if(this.content == '分数乘法') {
        ctnt = 11
      }
      else if(this.content == '分数除法') {
        ctnt = 12
      }
      else if(this.content == '带有百分数的计算') {
        ctnt = 13
      }
      let x, y, z, u
      let m = 0
      let mainContent = ''
      switch(ctnt) {
        case 0: 
          for(let i = 1; m <= this.counts - 1; i++) {
            let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + '\\times' + String(y) + '=">'
            x = Math.floor(Math.random()*(10))
            y = Math.floor(Math.random()*(1000))
            if(x !== 0 && y !== 0) {
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 1:
          for(let i = 1; m <= this.counts - 1; i++) {
            x = Math.floor(Math.random()*(1000))
            y = Math.floor(Math.random()*(10))
            if(x >= 10 && y >= 2) {
              x = Math.floor(x / y) * y
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + '\\div' + String(y) + '=">'
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 2: 
          for(let i = 1; m <= this.counts - 1; i++) {
            x = Math.floor(Math.random()*(100))
            y = Math.floor(Math.random()*(100))
            if(x >= 10 && y >= 0) {
              
              mainContent = mainContent + String(x) + '×' + String(y) + '='
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 3: 
          for(let i = 1; m <= this.counts - 1; i++) {
            x = Math.floor(Math.random()*(1000))
            y = Math.floor(Math.random()*(100))
            if(x >= 100 && y >= 10) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + '\\times' + String(y) + '=">'
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 4: 
          for(let i = 1; m <= this.counts - 1; i++) {
            console.log((i % 2 == 0? true : false))
            x = Math.floor(Math.random()*(1000))
            y = Math.floor(Math.random()*(100))
            if(x >= 100 && y >= 10) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + '\\div' + String(y) + '=">'
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 7: 
            for(let i = 1; m <= this.counts - 1; i++) {
            let pho = Math.floor(Math.random()*(2))
            console.log((i % 2 == 0? true : false))
            x = (Math.random()*(80)).toFixed(Math.floor((Math.random()*(2))))
            y = (Math.random()*(50)).toFixed(Math.floor((Math.random()*(3))))
            if(x !== 0 && y >= 0) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + (pho === 1? '+' : '-') + String(y) + '=">'
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 8: 
          for(let i = 1; m <= this.counts - 1; i++) {
            console.log((i % 2 == 0? true : false))
            x = (Math.random()*(80)).toFixed(Math.floor((Math.random()*(2))))
            y = (Math.random()*(50)).toFixed(Math.floor((Math.random()*(3))))
            if(x !== 0 && y !== 0) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + '\\times' + String(y) + '=">'
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 9 :
            for(let i = 1; m <= this.counts - 1; i++) {
            console.log((i % 2 == 0? true : false))
            x = (Math.random()*(80)).toFixed(Math.floor((Math.random()*(2))))
            y = (Math.random()*(50)).toFixed(Math.floor((Math.random()*(3))))
            if(x !== 0 && y !== 0) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?'+ String(x) + '\\div' + String(y) + '=">'
              mainContent = mainContent + skl
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 10: 
          for(let i = 1; m <= this.counts - 1; i++) {
            console.log((i % 2 == 0? true : false))
            x = Math.floor(Math.random()*(15))
            y = Math.floor(Math.random()*(10))
            z = Math.floor(Math.random()*(10))
            if(x !== 0 && y !== 0 && z !== 0 && u !== 0) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?\\frac{' + String(y) + '}{' + String(x) + '}' + (Math.floor(Math.random()*(2)) === 1? '+' : '-') +'\\frac{' + String(z) + '}{' + String(x) +'}=">'
              mainContent = mainContent + skl
              console.log(skl)
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 11 :
            for(let i = 1; m <= this.counts - 1; i++) {
            console.log((i % 2 == 0? true : false))
            x = Math.floor(Math.random()*(20))
            y = Math.floor(Math.random()*(20))
            z = Math.floor(Math.random()*(20))
            u = Math.floor(Math.random()*(20))
            if(x !== 0 && y !== 0 && z !== 0 && u !== 0) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?\\frac{' + String(y) + '}{' + String(x) + '}\\times\\frac{' + String(z) + '}{' + String(u) +'}=">'
              mainContent = mainContent + skl
              console.log(skl)
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 12 :
          for(let i = 1; m <= this.counts - 1; i++) {
            console.log((i % 2 == 0? true : false))
            x = Math.floor(Math.random()*(20))
            y = Math.floor(Math.random()*(20))
            z = Math.floor(Math.random()*(20))
            u = Math.floor(Math.random()*(20))
            if(x !== 0 && y !== 0 && z !== 0 && u !== 0) {
              let skl = '<img transition="fade-transition" src="http://latex.codecogs.com/gif.latex?\\frac{' + String(y) + '}{' + String(x) + '}\\div\\frac{' + String(z) + '}{' + String(u) +'}=">'
              mainContent = mainContent + skl
              console.log(skl)
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
          break
        case 13 :
          let fh = ['+', '-', '×', '÷']
          for(let i = 1; m <= this.counts - 1; i++) {
            let forh = Math.floor(Math.random()*(5))
            x = Math.floor(Math.random()*(100))
            y = Math.floor(Math.random()*(100))
            let chart
            if(forh === 1) {
              chart = fh[0]
            }
            else if(forh === 2) {
              chart = fh[1]
            }
            else if(forh === 3) {
              chart = fh[2]
            }
            else {
              chart = fh[3]
            }
            if(x !== 0 && y !== 0) {
              mainContent = mainContent + String(x) + (Math.floor(Math.random()*(2)) === 1? '%' : '') + chart + String(y) + (Math.floor(Math.random()*(2)) === 1? '%' : '') + '='
              m++
              if(m % 3 == 0) {
                mainContent += '<br><br>'
              }
              else {
                mainContent += '<span style="padding: 3em"></span>'
              }
            }
          }
        default: console.log('none')
      }
      this.all = mainContent
      setTimeout(() => {
        this.playing = false
      }, this.counts * 250)
    }
  }
}
</script>

